package main

import (
	"sort"
)

func solve(points [][]int64) int64 {
	yCount := make(map[int64]int64)
	for _, p := range points {
		y := p[1]
		yCount[y]++
	}

	counts := make([]int64, 0, len(yCount))
	for y := range yCount {
		counts = append(counts, yCount[y])
	}

	sort.Slice(counts, func(i, j int) bool {
		return counts[i] > counts[j]
	})

	MOD := int64(1e9 + 7)
	var total int64
	for i := 0; i < len(counts); i++ {
		for j := i + 1; j < len(counts); j++ {
			c1 := counts[i]
			c2 := counts[j]
			if c1 >= 2 && c2 >= 2 {
				comb1 := (c1 * (c1 - 1)) / 2
				comb2 := (c2 * (c2 - 1)) / 2
				product := (comb1 * comb2) % MOD
				total = (total + product) % MOD
			}
		}
	}

	return total
}
